// Input validation helpers
//
// Each validator returns an array of error strings. An empty array means the
// input passed validation. Callers typically concatenate arrays from several
// validators and, if the result is non-empty, return a 400 response.

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const NAME_MIN_LENGTH = 1;
const NAME_MAX_LENGTH = 100;
const EMAIL_MAX_LENGTH = 254;

/**
 * Verify each field in `requiredFields` is present (not undefined/null/'')
 * on the provided `source` object.
 */
function validateRequiredFields(source, requiredFields) {
  const errors = [];
  if (source == null || typeof source !== 'object') {
    return requiredFields.map((f) => `Missing required field: ${f}`);
  }
  for (const field of requiredFields) {
    const value = source[field];
    if (value === undefined || value === null || value === '') {
      errors.push(`Missing required field: ${field}`);
    }
  }
  return errors;
}

/**
 * Validate that `value` is a numeric id (integer > 0). Accepts numbers and
 * numeric strings (common for path/query params).
 */
function validateId(value, fieldName = 'id') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`${fieldName} is required`);
    return errors;
  }
  const asNumber = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(asNumber) || !Number.isInteger(asNumber) || asNumber <= 0) {
    errors.push(`${fieldName} must be a positive integer`);
  }
  return errors;
}

/**
 * Validate that `value` is a string whose length is in [min, max].
 */
function validateName(value, fieldName = 'name', min = NAME_MIN_LENGTH, max = NAME_MAX_LENGTH) {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`${fieldName} is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }
  if (value.length < min) {
    errors.push(`${fieldName} must be at least ${min} character${min === 1 ? '' : 's'}`);
  }
  if (value.length > max) {
    errors.push(`${fieldName} must be at most ${max} characters`);
  }
  return errors;
}

/**
 * Validate that `value` is a string, matches the email format, and is no
 * longer than `max` characters.
 */
function validateEmail(value, fieldName = 'email', max = EMAIL_MAX_LENGTH) {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`${fieldName} is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }
  if (value.length > max) {
    errors.push(`${fieldName} must be at most ${max} characters`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
  }
  return errors;
}

/**
 * Run a list of validator thunks and collect all resulting errors.
 * Each entry in `checks` should be a function returning an array of errors.
 */
function collectErrors(checks) {
  const errors = [];
  for (const check of checks) {
    const result = check();
    if (Array.isArray(result) && result.length > 0) {
      errors.push(...result);
    }
  }
  return errors;
}

/**
 * Express helper: if `errors` is non-empty, send a 400 JSON response and
 * return true (so the caller can early-return). Otherwise return false.
 */
function sendValidationError(res, errors) {
  if (errors && errors.length > 0) {
    res.status(400).json({
      error: 'Validation failed',
      details: errors,
    });
    return true;
  }
  return false;
}

module.exports = {
  EMAIL_REGEX,
  NAME_MIN_LENGTH,
  NAME_MAX_LENGTH,
  EMAIL_MAX_LENGTH,
  validateRequiredFields,
  validateId,
  validateName,
  validateEmail,
  collectErrors,
  sendValidationError,
};

