// validation.js
// Reusable input-validation helpers for API route handlers.
//
// Design goals:
//   * Pure functions — no side effects, no request/response coupling.
//   * Collect ALL failures before returning, so clients see every problem
//     in one 400 response instead of fixing errors one at a time.
//   * Small primitives (`checkRequired`, `checkType`, `checkLength`, ...)
//     compose into schema-style validators (`validateUserPayload`, ...).

'use strict';

// ---------------------------------------------------------------------------
// Constraints (exported so tests and route handlers can reuse the same limits)
// ---------------------------------------------------------------------------

const LIMITS = Object.freeze({
  NAME_MIN: 1,
  NAME_MAX: 100,
  EMAIL_MAX: 254, // RFC 5321 practical maximum
});

// Reasonably strict email regex. Not a full RFC 5322 parser (nobody uses that
// in practice) but rejects the common malformed inputs.
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ---------------------------------------------------------------------------
// Low-level primitives — each returns an error string or null.
// ---------------------------------------------------------------------------

function checkRequired(value, field) {
  if (value === undefined || value === null || value === '') {
    return `${field} is required`;
  }
  return null;
}

function checkString(value, field) {
  if (typeof value !== 'string') {
    return `${field} must be a string`;
  }
  return null;
}

function checkLength(value, field, min, max) {
  // Only meaningful if value is already a string; caller should check type first.
  if (typeof value !== 'string') return null;
  if (value.length < min || value.length > max) {
    return `${field} must be between ${min} and ${max} characters`;
  }
  return null;
}

function checkEmailFormat(value, field) {
  if (typeof value !== 'string') return null;
  if (!EMAIL_RE.test(value)) {
    return `${field} must be a valid email address`;
  }
  return null;
}

// `id` arrives from req.params as a string; accept numeric strings and
// coerce, but reject anything that isn't a positive integer.
function checkNumericId(value, field) {
  if (value === undefined || value === null || value === '') {
    return `${field} is required`;
  }
  const str = String(value);
  if (!/^\d+$/.test(str)) {
    return `${field} must be a numeric value`;
  }
  const n = Number(str);
  if (!Number.isInteger(n) || n <= 0) {
    return `${field} must be a positive integer`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composite field validators — push any error(s) for a single field.
// ---------------------------------------------------------------------------

function validateName(value, errors, field = 'name') {
  const reqErr = checkRequired(value, field);
  if (reqErr) { errors.push(reqErr); return; }

  const typeErr = checkString(value, field);
  if (typeErr) { errors.push(typeErr); return; }

  const lenErr = checkLength(value, field, LIMITS.NAME_MIN, LIMITS.NAME_MAX);
  if (lenErr) errors.push(lenErr);
}

function validateEmail(value, errors, field = 'email') {
  const reqErr = checkRequired(value, field);
  if (reqErr) { errors.push(reqErr); return; }

  const typeErr = checkString(value, field);
  if (typeErr) { errors.push(typeErr); return; }

  // Length before format so "too long" beats "invalid format" for huge inputs.
  const lenErr = checkLength(value, field, 1, LIMITS.EMAIL_MAX);
  if (lenErr) errors.push(lenErr);

  const fmtErr = checkEmailFormat(value, field);
  if (fmtErr) errors.push(fmtErr);
}

function validateId(value, errors, field = 'id') {
  const err = checkNumericId(value, field);
  if (err) errors.push(err);
}

// ---------------------------------------------------------------------------
// Schema-level validators used by routes.
// Each returns { valid: bool, errors: string[] }.
// ---------------------------------------------------------------------------

// POST /users — full payload required.
function validateUserPayload(body) {
  const errors = [];
  if (!body || typeof body !== 'object') {
    return { valid: false, errors: ['request body must be a JSON object'] };
  }
  validateName(body.name, errors);
  validateEmail(body.email, errors);
  return { valid: errors.length === 0, errors };
}

// PUT /users/:id — same body rules as create, plus a valid id param.
function validateUserUpdate(params, body) {
  const errors = [];
  validateId(params && params.id, errors);

  if (!body || typeof body !== 'object') {
    errors.push('request body must be a JSON object');
    return { valid: false, errors };
  }
  validateName(body.name, errors);
  validateEmail(body.email, errors);
  return { valid: errors.length === 0, errors };
}

// GET /users/:id — only the id needs checking.
function validateIdParam(params) {
  const errors = [];
  validateId(params && params.id, errors);
  return { valid: errors.length === 0, errors };
}

// ---------------------------------------------------------------------------
// Express middleware factory.
//   app.post('/users', validate(validateUserPayload, 'body'), handler)
// ---------------------------------------------------------------------------

function validate(validatorFn, source = 'body') {
  return (req, res, next) => {
    let result;
    if (source === 'body')         result = validatorFn(req.body);
    else if (source === 'params')  result = validatorFn(req.params);
    else if (source === 'both')    result = validatorFn(req.params, req.body);
    else                           result = validatorFn(req[source]);

    if (!result.valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: result.errors,
      });
    }
    next();
  };
}

module.exports = {
  LIMITS,
  // primitives
  checkRequired,
  checkString,
  checkLength,
  checkEmailFormat,
  checkNumericId,
  // field validators
  validateName,
  validateEmail,
  validateId,
  // schema validators
  validateUserPayload,
  validateUserUpdate,
  validateIdParam,
  // middleware
  validate,
};

